from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

def verify_jwt(token, secret_or_public_key, algorithm):
    try:
        # Verify the JWT token with the given secret or public key and algorithm
        payload = jwt.decode(
            token,
            secret_or_public_key,
            algorithms=[algorithm]
        )
        return payload
    except jwt.ExpiredSignatureError:
        return {'error': 'Token expired'}, 401
    except jwt.InvalidTokenError:
        return {'error': 'Invalid token'}, 401

@app.route('/verify-token', methods=['POST'])
def verify_token():
    # Get the token and algorithm from request headers or body
    token = request.headers.get('Authorization').split()[1]
    algorithm = request.headers.get('Algorithm')
    
    if not algorithm:
        return {'error': 'Algorithm not specified'}, 400
    
    # Define different secrets or public keys for each algorithm
    if algorithm == 'HS256':
        secret_key = 'your_hs256_secret_key'
    elif algorithm == 'RS256':
        with open('public_rsa.pem', 'r') as f:
            public_key = f.read()
        secret_or_public_key = public_key
    else:
        return {'error': 'Unsupported algorithm'}, 400
    
    # Verify the token and extract payload
    payload = verify_jwt(token, secret_or_public_key, algorithm)
    
    if isinstance(payload, dict) and 'error' in payload:
        return payload
    else:
        return jsonify(payload)

